INSERT OR IGNORE INTO collections (id, slug, name, description) VALUES ('col_edition_01', 'edition-01', 'Édition N°01', 'The inaugural collection — four fragrances rooted in Indian materials and rituals.');
INSERT OR IGNORE INTO products (id, slug, name, tagline, description, story, price, stock, active, scent_family, scent_notes, concentration, size, hue, "index", collection_id, is_discovery_set) VALUES ('prod_mogra_noir', 'mogra-noir', 'Mogra Noir', 'A monsoon evening, jasmine in bloom.', 'Picked at dawn from gardens outside Madurai, mogra opens with quiet intensity — sweet, narcotic, alive. We pair it with smoked amber for the hours after sunset.', 'Picked at dawn from gardens outside Madurai, mogra opens with quiet intensity — sweet, narcotic, alive. We pair it with smoked amber for the hours after sunset.', 480000, 50, 1, 'Floral · Warm', '{"top":["Bergamot","Pink Pepper"],"heart":["Mogra (Indian Jasmine)","Tuberose"],"base":["Amber","White Musk"]}', 'EDP', '50ml', '#C4622D', '01', 'col_edition_01', 0);
INSERT OR IGNORE INTO products (id, slug, name, tagline, description, story, price, stock, active, scent_family, scent_notes, concentration, size, hue, "index", collection_id, is_discovery_set) VALUES ('prod_oud_vara', 'oud-vara', 'Oud Vārā', 'Smoke, leather, and the patience of wood.', 'Vārā means circle, the slow turning of seasons. Aged oud from Assam meets Bulgarian rose — a fragrance that deepens, hour by hour, into something quietly devotional.', 'Vārā means circle, the slow turning of seasons. Aged oud from Assam meets Bulgarian rose — a fragrance that deepens, hour by hour, into something quietly devotional.', 680000, 30, 1, 'Woody · Resinous', '{"top":["Saffron","Cardamom"],"heart":["Assam Oud","Damask Rose"],"base":["Sandalwood","Tobacco"]}', 'EDP', '50ml', '#7A3B1F', '02', 'col_edition_01', 0);
INSERT OR IGNORE INTO products (id, slug, name, tagline, description, story, price, stock, active, scent_family, scent_notes, concentration, size, hue, "index", collection_id, is_discovery_set) VALUES ('prod_sandal_velvet', 'sandal-velvet', 'Sandal Velvet', 'Mysore sandalwood, rendered into stillness.', 'Sandalwood is the scent of meditation halls and grandmother''s wardrobes. Soft, warm, intimate — a fragrance that listens before it speaks.', 'Sandalwood is the scent of meditation halls and grandmother''s wardrobes. Soft, warm, intimate — a fragrance that listens before it speaks.', 540000, 40, 1, 'Woody · Creamy', '{"top":["Coriander","Iris"],"heart":["Mysore Sandalwood","Vetiver"],"base":["Cashmeran","Vanilla Bourbon"]}', 'EDP', '50ml', '#A98F6F', '03', 'col_edition_01', 0);
INSERT OR IGNORE INTO products (id, slug, name, tagline, description, story, price, stock, active, scent_family, scent_notes, concentration, size, hue, "index", collection_id, is_discovery_set) VALUES ('prod_chai_atelier', 'chai-atelier', 'Chai Atelier', 'A morning ritual, bottled.', 'The first cup of chai at a roadside stall in Varanasi — steam, spice, and the hush before the city wakes. Equal parts comfort and curiosity.', 'The first cup of chai at a roadside stall in Varanasi — steam, spice, and the hush before the city wakes. Equal parts comfort and curiosity.', 420000, 45, 1, 'Gourmand · Spiced', '{"top":["Black Cardamom","Cinnamon Bark"],"heart":["Assam Tea Leaf","Ginger"],"base":["Tonka Bean","Brown Sugar"]}', 'EDP', '50ml', '#A06A2D', '04', 'col_edition_01', 0);
INSERT OR IGNORE INTO products (id, slug, name, tagline, description, story, price, stock, active, scent_family, scent_notes, concentration, size, hue, "index", collection_id, is_discovery_set) VALUES ('prod_discovery_set', 'discovery-set', 'Discovery Set', 'All four fragrances. 2ml each.', 'Begin here. Four 2ml vials of every fragrance in the YUN collection — Mogra Noir, Oud Vārā, Sandal Velvet, and Chai Atelier. Hand-packed in a linen pouch.', 'Begin here. The best way to find your fragrance is to wear it for a full day.', 149900, 100, 1, 'Sampler', NULL, NULL, '4 × 2ml', '#4a6fa5', '00', 'col_edition_01', 1);
